```csharp
public static class DbContextExtensions
{
    public static void Upsert<T>(this DbContext dbContext, T entity, Expression<Func<T, object>> matchExpression) where T : class
    {
        var dbSet = dbContext.Set<T>();

        // 创建一个表达式访问器以获取匹配表达式的成员信息
        var memberExpression = matchExpression.Body as MemberExpression;
        if (memberExpression == null)
        {
            var unaryExpression = matchExpression.Body as UnaryExpression;
            memberExpression = unaryExpression.Operand as MemberExpression;
        }

        // 构建一个用于查找匹配实体的表达式方法
        var parameter = Expression.Parameter(typeof(T));
        var equalityExpression = Expression.Equal(Expression.Property(parameter, memberExpression.Member.Name), Expression.Property(Expression.Constant(entity), memberExpression.Member.Name));
        var lambdaExpression = Expression.Lambda<Func<T, bool>>(equalityExpression, parameter);

        // 检查数据库中是否存在匹配的实体
        var existingEntity = dbSet.FirstOrDefault(lambdaExpression);

        if (existingEntity != null)
        {
            // 更新现有实体
            dbContext.Entry(existingEntity).CurrentValues.SetValues(entity);
        }
        else
        {
            // 添加新实体
            dbSet.Add(entity);
        }
    }
}
```

使用上述扩展方法，您可以在使用EF Core时执行Upsert操作。以下是一个示例：

